import { LuCopy, LuCheck } from 'react-icons/lu';

export default function RssFeedWidget() {
  const [copied, setCopied] = useState(false);
  const feedUrl = `${siteConfig.baseUrl.replace(/\/+$/, '')}/feed.xml`;

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(feedUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // clipboard API not available
    }
  };

  return (
    <div className="flex items-center gap-2 px-3 py-2.5 my-4 rounded-lg bg-muted/5 border border-muted/15 not-prose">
      <code className="text-xs font-mono text-muted/60 flex-1 truncate">{feedUrl}</code>
      <button
        onClick={handleCopy}
        className="flex-shrink-0 flex items-center gap-1.5 text-xs text-muted/60 hover:text-accent transition-colors"
        aria-label="Copy feed URL"
      >
        {copied
          ? <><LuCheck className="w-3.5 h-3.5 text-accent" /><span className="text-accent">Copied!</span></>
          : <><LuCopy className="w-3.5 h-3.5" /><span>Copy</span></>
        }
      </button>
    </div>
  );
}
```

**Key features:**
- Client-side component (React hook for copy state)
- Displays feed URL in formatted code block
- Copy-to-clipboard functionality with visual feedback
- Accessible button with aria-label
- Responsive design with Tailwind CSS

#### 3. **MarkdownRenderer Integration** (referenced in `/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/components/MarkdownRenderer.tsx`)

```typescript
// Line 133
const allComponents = { ...components, 'rss-feed': () => <RssFeedWidget /> } as any;
```

This allows MDX/Markdown content to embed the RSS widget using `<rss-feed />` tag.

### Configuration References

#### 4. **Site Config** (`/Users/hutusi/workspace/ai/naive/amytis-claude-review/site.config.ts`)

- **Line 77**: Footer link `{ name: "RSS Feed", url: "/feed.xml", weight: 3 }`
- **Line 36**: Uses `siteConfig.baseUrl` for absolute feed URL generation

### Internationalization Support

#### 5. **Translations** (`/Users/hutusi/workspace/ai/naive/amytis-claude-review/src/i18n/translations.ts`)

**English (lines 31, 93-94):**
```typescript
rss_feed: "RSS Feed",
rss_readers: "RSS Readers",
rss_description: "Subscribe with any RSS reader for automatic updates when new content is published.",
```

**Chinese (lines 163, 225-226):**
```typescript
