    80→export function calculateReadingTime(content: string): string {
    81→  const wordsPerMinute = 200;
    82→  const hanCharsPerMinute = 300;
    83→
    84→  // Strip tags and common markdown syntax before counting.
    85→  const text = content
    86→    .replace(/<\/?[^>]+(>|$)/g, "")
    87→    .replace(/```[\s\S]*?```/g, "")
    88→    .replace(/`[^`]*`/g, "")
    89→    .replace(/!\[[^\]]*\]\([^)]+\)/g, "")
    90→    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    91→    .replace(/[#*_~>\-[\]()]/g, " ");
    92→
    93→  const hanCharCount = (text.match(/[\u3400-\u4DBF\u4E00-\u9FFF\uF900-\uFAFF]/g) || []).length;
    94→  const latinWordCount = (text.match(/[A-Za-z0-9]+(?:['’-][A-Za-z0-9]+)*/g) || []).length;
    95→
    96→  const estimatedMinutes = (latinWordCount / wordsPerMinute) + (hanCharCount / hanCharsPerMinute);
    97→  const minutes = Math.max(1, Math.ceil(estimatedMinutes));
    98→  return `${minutes} min read`;
    99→}
   100→
   101→export function generateExcerpt(content: string): string {
   102→  let plain = content.replace(/^#+\s+/gm, '');
   103→  plain = plain.replace(/```[\s\S]*?```/g, '');
   104→  plain = plain.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
   105→  plain = plain.replace(/\*\[([^\]]+)\*\]\([^)]+\)/g, '$1');
   106→  plain = plain.replace(/(\$\*\*|__|\*|_)/g, '');
   107→  plain = plain.replace(/`([^`]+)`/g, '$1');
   108→  plain = plain.replace(/^>\s+/gm, '');
   109→  plain = plain.replace(/\s+/g, ' ').trim();
   110→  
   111→  if (plain.length <= 160) {
   112→    return plain;
   113→  }
   114→  return plain.slice(0, 160).trim() + '...';
   115→}
   116→
   117→export function getHeadings(content: string): Heading[] {
   118→  const regex = /^(#{2,3})\s+(.*)$/gm;
   119→  const headings: Heading[] = [];
   120→  const slugger = new GithubSlugger();
   121→  let match;
   122→
   123→  while ((match = regex.exec(content)) !== null) {
   124→    const level = match[1].length;
   125→    const text = match[2].trim();
   126→    const id = slugger.slug(text);
   127→    
   128→    headings.push({ id, text, level });
   129→  }
   130→  return headings;
   131→}
